/* tslint:disable */

import { isNullOrUndefined } from './utils';
import customParseFormat from 'dayjs/plugin/customParseFormat';
import dayjs from 'dayjs';
dayjs.extend(customParseFormat);

export { };

declare global {
  interface Date {
    addDays(days: number): Date;

    addWeeks(weeks: number): Date;

    addMinutes(minutes: number): Date;

    addYears(years: number): Date;

    getSunday(date: Date): Date;

    isLeapYear(): boolean;

    dateEquals(date: Date): boolean;

    daysDifference(other: Date): number;

    isBefore(other: Date): boolean;

    isAfter(other: Date): boolean;
  }
}

Date.prototype.addDays = function (days: number): Date {
  const dat = new Date(this.valueOf());
  dat.setDate(dat.getDate() + days);
  return dat;
};

Date.prototype.addWeeks = function (weeks: number): Date {
  const dat = new Date(this.valueOf());
  dat.setDate(dat.getDate() + weeks * 7);
  return dat;
};

Date.prototype.addYears = function (years: number): Date {
  const dat = new Date(this.valueOf());
  dat.setFullYear(dat.getFullYear() + years);
  return dat;
};

Date.prototype.addMinutes = function (minutes: number): Date {
  const dat = new Date(this.valueOf());
  dat.setMinutes(dat.getMinutes() + minutes);
  return dat;
};

Date.prototype.getSunday = function (inputDate: Date): Date {
  const d = new Date(inputDate);
  const day = d.getDay();
  const diff = d.getDate() - day + (day === 0 ? -6 : 0);
  return new Date(d.setDate(diff));
};

Date.prototype.isLeapYear = function (): boolean {
  const year = new Date(this.valueOf()).getFullYear();
  return (year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;
};

Date.prototype.dateEquals = function (pDate): boolean {
  return (
    this.getFullYear() === pDate.getFullYear() &&
    this.getMonth() === pDate.getMonth() &&
    this.getDate() === pDate.getDate()
  );
};

Date.prototype.daysDifference = function (otherDate: Date): number {
  const MS_PER_DAY: number = 1000 * 60 * 60 * 24;
  const diff_milli: number = this.getTime() - otherDate.getTime();
  return Math.round(diff_milli / MS_PER_DAY);
};

Date.prototype.isBefore = function (otherDate: Date): boolean {
  if (isNullOrUndefined(otherDate)) {
    return null;
  }
  return this.getTime() < otherDate.getTime();
};

Date.prototype.isAfter = function (otherDate: Date): boolean {
  if (isNullOrUndefined(otherDate)) {
    return null;
  }
  return this.getTime() > otherDate.getTime();
};

/** Checks that the date string is in either of the following formats:
 * MM/DD/YYYY or YYYY-MM-DD
 */
export function isValidGregorianDateString(selectedDate: string) {
  // Slicing till 10 so we only include the date, not any time the user may be passing in as well.
  // Shared Services uses the YYYY-MM-DD format, so we're adding support for that too.
  const date = selectedDate.slice(0, 10);
  return (
    dayjs(date, 'MM/DD/YYYY', true).isValid() ||
    dayjs(date, 'YYYY-MM-DD', true).isValid() ||
    dayjs(date, 'MM-DD-YYYY', true).isValid()
  );
}

export function isValidFiscalDateString(selectedDate: string) {
  // Slicing till 10 so we only include the date, not any time the user may be passing in as well.
  // Shared Services uses the YYYY-MM-DD format, so we're adding support for that too.
  const fiscalRegex = /^\d{4}\/P\d+\/W\d+\/(Su|Mo|Tu|We|Th|Fr|Sa)/;
  return fiscalRegex.test(selectedDate);
}

export function isValidDateString(selectedDate: string) {
  return isValidGregorianDateString(selectedDate) || isValidFiscalDateString(selectedDate);
}

/** Returns the time in HH:mm format. */
export function getTime(date: Date) {
  return dayjs(date).format('HH:mm');
}
