export const calculateFiscalStart = (date: Date): Date => {
  const firstDayOfYear = new Date(date.getFullYear(), 0, 1);
  const firstDayOfWeekOfYear = firstDayOfYear.getDay();
  const firstSundayOfYear =
    firstDayOfWeekOfYear === 0 ? firstDayOfYear : firstDayOfYear.addDays(DAYS_IN_WEEK - firstDayOfWeekOfYear);
  return firstSundayOfYear.addWeeks(4);
};

export const calculateYearStartAndEnd = (date: Date, dateOffset: number) => {
  let start = calculateFiscalStart(date).addDays(dateOffset);
  let followingYear = new Date(date.getFullYear() + 1, 0, 1);
  let end = calculateFiscalStart(followingYear).addDays(-1);
  if (start > date) {
    const newDate = date.addYears(-1);
    start = calculateFiscalStart(newDate).addDays(dateOffset);
    followingYear = new Date(date.getFullYear(), 0, 1);
    end = calculateFiscalStart(followingYear).addDays(-1);
    end.setHours(23, 59, 59);
    return { calYear: newDate.getFullYear(), start, end: end.addDays(dateOffset) };
  }
  end.setHours(23, 59, 59);
  return { calYear: date.getFullYear(), start, end: end.addDays(dateOffset) };
};

export const calculateQuarterByPeriod = (periodNumber: number): number => {
  let quarter = 0;
  switch (true) {
    case periodNumber <= 4:
      quarter = 1;
      break;
    case periodNumber <= 7:
      quarter = 2;
      break;
    case periodNumber <= 10:
      quarter = 3;
      break;
    case periodNumber <= 13:
      quarter = 4;
      break;
    default:
      quarter = 1;
      break;
  }
  return quarter;
};

export const calculatePeriods = (yearStart: Date, yearEnd: Date): Period[] => {
  const periods: Period[] = [];

  for (let index = 0; index < PERIODS_PER_YR; index++) {
    let start = yearStart;
    let end = yearEnd;
    if (index === 0) {
      end = start.addDays(DAYS_IN_WEEK * PERIOD_WEEK_COUNT).addDays(-1);
    } else {
      start = periods[index - 1].endDate.addDays(1);
      start.setHours(0, 0, 0);
      end = start.addDays(DAYS_IN_WEEK * PERIOD_WEEK_COUNT).addDays(-1);
    }

    if (index === 12) {
      end = yearEnd;
    }

    end = new Date(end.setHours(23, 59, 59));

    periods.push({
      period: index + 1,
      startDate: start,
      endDate: end,
      year: yearStart.getFullYear(),
      quarter: calculateQuarterByPeriod(index + 1)
    });
  }
  return periods;
};

export const calculateWeeks = (yearStart: Date, yearEnd: Date) => {
  const weeks: Week[] = [];
  const periods: Period[] = calculatePeriods(yearStart, yearEnd);

  const totalNumberOfFiscalWeeks =
    Math.floor((yearEnd.getTime() - yearStart.getTime()) / (ONE_DAY_MS * DAYS_IN_WEEK)) + 1;
  for (let weekNum = 0; weekNum < totalNumberOfFiscalWeeks; weekNum++) {
    const weekStartDate = yearStart.addWeeks(weekNum);
    let weekEndDate = weekStartDate.addDays(6);

    if (weekNum === totalNumberOfFiscalWeeks - 1) {
      weekEndDate = yearEnd;
    }

    weekEndDate.setHours(23, 59, 59);
    const periodOfWk = periods.find((pd) => weekStartDate >= pd.startDate && weekStartDate <= pd.endDate);

    weeks.push({
      week: weekNum + 1,
      startDate: weekStartDate,
      endDate: weekEndDate,
      period: periodOfWk.period
    });
  }
  return { periods, weeks };
};

export const calculateQuarters = (yearStart: Date, yearEnd: Date) => {
  const { periods, weeks } = calculateWeeks(yearStart, yearEnd);
  const quarters: Quarter[] = [];
  for (let q = 1; q <= 4; q++) {
    const periodsOfQuarter = periods.filter((period) => period.quarter === q);
    periodsOfQuarter.forEach((period) => {
      period.weeks = weeks.filter((week) => {
        if (week.startDate >= period.startDate && week.endDate <= period.endDate) {
          return week;
        }
      });
    });
    quarters.push({
      quarter: q,
      startDate: periodsOfQuarter[0].startDate,
      endDate: periodsOfQuarter[periodsOfQuarter.length - 1].endDate,
      periods: periodsOfQuarter
    });
  }
  return { quarters, periods, weeks };
};

/**
 * This function get's called when user change/select year from the dropdown in the calendar.
 * This function handles building calendar year and doesn't take user selected into account (hence the function name) as it's redundent,
 *  in the sense that for building a calendar year all we need is for which year.
 * Here, you might be wondering why month is hardcoded to 6.
 *  1. Let's understand why this function was created,
 *    a. Kroger Ad calendar year starts in Feb and ends in Feb,
 *    b. If user selects date as Jan 15 2022, which belongs to Ad calendar year 2021,
 *    c. Let's say now user changes year from 2021 to 2022 in calendar,
 *    d. We'll update the year of the selected date to 2022.
 *        Here is the catch, earlier, year was 2022 in the selected date and now we are updating it to 2022.
 *    e. Even when user selects 2022 as year we ar building 2021 calendar year(refer 1.b) which is incorrect.
 *        Now, to fix this issue this function was created.
 *  2. To fix the above issue we are setting month to 6.
 *    As we are considering current date in this function with month as 6 and setting the user selected year (2022 from above example),
 *    date will be Jul xx 2022 which belongs to 2022 Ad calendar year.
 *  3. Here we can set month anywhere between 2 (Mar) to 11 (Dec) (as calendar year starts and ends in Feb).
 * @param year - calendar year to build
 * @param dateOffset - date offset
 * @returns - CalYear
 */
export const buildCalendarYearWithoutDate = (year: number, dateOffset: number = 0): CalYear => {
  const midYearDate = new Date();
  midYearDate.setMonth(6);
  midYearDate.setFullYear(year);
  return buildCalendarYear(midYearDate, dateOffset);
};

/**
 * Calculates the fiscal year (5th Sunday of every new year) and any subset of year cycles given a date offset
 * Ad/Promo Calendar (Wed-Tues) starts Wednesday after first fiscal Sunday
 * @param dateVal Date OR number
 * @param dateOffset <Optional> defaults to 0
 * @return CalYear containing year start, year end and all quarter, period, and week arrays for given year
 */
export const buildCalendarYear = (dateVal: Date | number, dateOffset: number = 0): CalYear => {
  const currentDate = typeof dateVal === 'number' ? new Date(dateVal + 1, 0, 1) : dateVal;
  const calYear = calculateYearStartAndEnd(currentDate, dateOffset);
  const { quarters, periods, weeks } = calculateQuarters(calYear.start, calYear.end);
  return {
    calYear: calYear.calYear,
    startDate: calYear.start,
    endDate: calYear.end,
    periods,
    weeks,
    quarters
  };
};

export const buildTimePickerCalendarYear = (dateVal: Date | number, dateOffset: number = 0): CalYear => {
  if (dateVal === -1) {
    const currentDate = new Date();
    const calYear = calculateYearStartAndEnd(currentDate, dateOffset);
    const { quarters, periods, weeks } = calculateQuarters(calYear.start, calYear.end);
    return {
      calYear: null,
      startDate: calYear.start,
      endDate: calYear.end,
      periods,
      weeks,
      quarters
    };
  } else {
    const currentDate = typeof dateVal === 'number' ? new Date(dateVal + 1, 0, 1) : dateVal;
    const calYear = calculateYearStartAndEnd(currentDate, dateOffset);
    const { quarters, periods, weeks } = calculateQuarters(calYear.start, calYear.end);
    return {
      calYear: calYear.calYear,
      startDate: calYear.start,
      endDate: calYear.end,
      periods,
      weeks,
      quarters
    };
  }
};

/**
 * @description Calculates and returns the number of the fiscal year given the date
 * @param date Date
 * @param dateOffset <Optional> defaults to 0
 * @return year number
 */
export const findYearByDate = (date: Date, dateOffset: number = 0): number => {
  const yearStart = calculateYearStartAndEnd(date, dateOffset);
  return yearStart.start.getFullYear();
};

/**
 * @description Calculates and returns quarter given date and date offset to determine calendar type (Promo/Fiscal/etc)
 * @param date Date
 * @param dateOffset number:  <Optional> defaults to 0
 * @return Quarter object
 */
export const findQuarterByDate = (date: Date, dateOffset: number = 0): Quarter => {
  const year = calculateYearStartAndEnd(date, dateOffset);
  const quarters = calculateQuarters(year.start, year.end).quarters;
  return quarters.find((qt) => date >= qt.startDate && date <= qt.endDate);
};

/**
 * @description Calculates and returns period given date and date offset to determine calendar type (Promo/Fiscal/etc)
 * @param date Date
 * @param dateOffset number: <Optional> defaults to 0
 * @return Period object
 */
export const findPeriodByDate = (date: Date, dateOffset: number = 0): Period => {
  const year = calculateYearStartAndEnd(date, dateOffset);
  const periods = calculatePeriods(year.start, year.end);
  return periods.find((period) => date >= period.startDate && date <= period.endDate);
};

/**
 * @description Calculates and returns array of periods given a quarter, and optional date and date offset parameters
 * @param quarter number
 * @param date Date: <Optional> defaults to Date.now()
 * @param dateOffset number: <Optional> defaults to 0
 */
export const findPeriodsByQuarter = (quarter: number, date?: Date, dateOffset: number = 0): Period[] => {
  date = date || new Date(Date.now());
  const year = calculateYearStartAndEnd(date, dateOffset);
  const periods = calculatePeriods(year.start, year.end);
  return periods.filter((period) => period.quarter === quarter);
};

/**
 * @description Calculates and returns week given date and date offset to determine calendar type (Promo/Fiscal/etc)
 * @param date Date
 * @param dateOffset number: <Optional> defaults to 0
 * @return Week object
 */

export const findWeekByDate = (date: Date, dateOffset: number = 0): Week => {
  const year = calculateYearStartAndEnd(date, dateOffset);
  const weeks = calculateWeeks(year.start, year.end).weeks;
  return weeks.find((week) => date >= week.startDate && date <= week.endDate);
};

/**
 * @description Calculates and returns array of Weeks within a specified period, and optional date and date offset parameters
 * @param period number
 * @param date Date: <Optional> defaults to Date.now()
 * @param dateOffset number: <Optional> defaults to 0
 */
export const findWeeksByPeriod = (period: number, date?: Date, dateOffset: number = 0): Week[] => {
  date = date || new Date(Date.now());
  const year = calculateYearStartAndEnd(date, dateOffset);
  const weeks = calculateWeeks(year.start, year.end).weeks;
  return weeks.filter((week) => week.period === period);
};

/**
 * @description Calculates and returns array of Weeks within a specified quarter, and optional date and date offset parameters
 * @param quarter number
 * @param date Date: <Optional> defaults to Date.now()
 * @param dateOffset number: <Optional> defaults to 0
 */
export const findWeeksByQuarter = (quarter: number, date?: Date, dateOffset: number = 0): Week[] => {
  date = date || new Date(Date.now());
  const year = calculateYearStartAndEnd(date, dateOffset);
  const { quarters, weeks } = calculateQuarters(year.start, year.end);
  const periodsInQuarter = quarters[quarter - 1].periods;
  let weeksInQuarter = [];

  periodsInQuarter.forEach((pd) => {
    weeksInQuarter = [...weeksInQuarter, ...weeks.filter((week) => week.period === pd.period)];
  });
  return weeksInQuarter;
};

