export const dateConst: IDateConst = {
  minutesSteps: [1, 15, 30, 60],
  dateFormat: 'MM/DD/YYYY',
  maxMonthIndex: 11,
  startOfEpoch: new Date(Date.UTC(1970, 0, 1, 0, 0, 0, 0)),
  endOfEpoch: new Date(Date.UTC(2038, 0, 19, 3, 14, 7, 0)),
  daysOfWeek1stLetters: [
    WeekDay1stLetters.SUNDAY,
    WeekDay1stLetters.MONDAY,
    WeekDay1stLetters.TUESDAY,
    WeekDay1stLetters.WEDNESDAY,
    WeekDay1stLetters.THURSDAY,
    WeekDay1stLetters.FRIDAY,
    WeekDay1stLetters.SATURDAY
  ],
  daysOfWeekNames: [
    WeekDayNames.SUNDAY,
    WeekDayNames.MONDAY,
    WeekDayNames.TUESDAY,
    WeekDayNames.WEDNESDAY,
    WeekDayNames.THURSDAY,
    WeekDayNames.FRIDAY,
    WeekDayNames.SATURDAY
  ],
  daysOfWeekFullNames: [
    WeekDayFullNames.SUNDAY,
    WeekDayFullNames.MONDAY,
    WeekDayFullNames.TUESDAY,
    WeekDayFullNames.WEDNESDAY,
    WeekDayFullNames.THURSDAY,
    WeekDayFullNames.FRIDAY,
    WeekDayFullNames.SATURDAY
  ],
  monthNames: [
    MonthNames.JANUARY,
    MonthNames.FEBRUARY,
    MonthNames.MARCH,
    MonthNames.APRIL,
    MonthNames.MAY,
    MonthNames.JUN,
    MonthNames.JULY,
    MonthNames.AUGUST,
    MonthNames.SEPTEMBER,
    MonthNames.OCTOBER,
    MonthNames.NOVEMBER,
    MonthNames.DECEMBER
  ],
  outOfRangeErrorMessage: 'Date is outside of the min and max range',

  dateIsInvalid: (date: Date) => date == null || date.toString() === 'Invalid Date',
  rangeIncluding: (start: number, stop: number, step: number = 1): Array<number> => {
    return Array(Math.ceil((stop - start) / step) + 1)
      .fill(start)
      .map((x, y) => x + y * step);
  },
  isSameDate: (date1: Date, date2: Date): boolean => {
    return (
      date1 != null &&
      date2 != null &&
      !dateConst.dateIsInvalid(date1) &&
      !dateConst.dateIsInvalid(date2) &&
      date1.getFullYear() === date2.getFullYear() &&
      date1.getMonth() === date2.getMonth() &&
      date1.getDate() === date2.getDate()
    );
  },
  formatDate: (date: Date): string => {
    return date == null ? '' : [
      (date.getMonth() + 1 + '').padStart(2, '0'),
      (date.getDate() + '').padStart(2, '0'),
      date.getFullYear()
    ].join('/');
  },
  formatTime: (date: Date): string => {
    if (isNullOrUndefined(date)) {
      return undefined;
    }
    return date.toLocaleString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      hour12: false
    });
  },
  getTimeEntries: (minutesIncrement: string): Array<Item> => {
    // eslint-disable-next-line max-len
    let mIncrement: MinutesSteps = stringUtils.isBlank(minutesIncrement) ? dateConst.minutesSteps[3] as MinutesSteps : parseInt(minutesIncrement, 10) as MinutesSteps;
    if (isNaN(mIncrement) || dateConst.minutesSteps.indexOf(mIncrement) < 0) {
      // eslint-disable-next-line max-len
      console.warn(`minutesIncrement property is invalid ${minutesIncrement}, will default to ${dateConst.minutesSteps[3]}`);
      mIncrement = dateConst.minutesSteps[3] as MinutesSteps;
    }
    const timeEntries: Array<Item> = [];
    Object.keys(DayParts).forEach((dayPart: DayParts) =>
      [12, ...dateConst.rangeIncluding(1, 11)].forEach((h: number) => {
        const isTwelve: boolean = h === 12;
        dateConst.rangeIncluding(0, (dateConst.minutesSteps[3] / mIncrement) - 1).forEach((rItem: number) => {
          const minute: number = rItem * mIncrement;
          const hour: number = dayPart === DayParts.AM ? (isTwelve ? 0 : h) : (isTwelve ? 12 : h + 12);
          timeEntries.push({
            label: `${(h + '').padStart(2, '0')}:${(minute + '').padStart(2, '0')} ${dayPart}`,
            value: { hour: hour, minute: minute }
          });
        });
      })
    );

    return timeEntries;
  },
  getStartTime: (startTime: string, selectedDate: string | Date = null): ITimeEntry => {
    const selectedTime: string = startTime || dateConst.formatTime(dateConst.selectedDateToDate(selectedDate));
    if (!isNullOrUndefinedOrEmptyString(selectedTime)) {
      const [hour, minute] = selectedTime.slice(0, 5).split(':');
      const hourNum: number = parseInt(hour, 10);
      const minuteNum: number = parseInt(minute, 10);
      if (!isNaN(hourNum) && hourNum >= 0 && hourNum < 24 && !isNaN(minuteNum) && minuteNum >= 0 && minuteNum < 60) {
        return { hour: hourNum, minute: minuteNum };
      }
    }
    return null;
  },
  selectedDateToString: (date: string | Date): string => {
    if (typeof date === 'string') {
      return dateConst.formatDate(new Date(date));
    } else if (date instanceof Date) {
      return dateConst.formatDate(date);
    } else {
      return undefined;
    }
  },
  selectedDateToDate: (date: string | Date): Date => {
    if (typeof date === 'string') {
      return new Date(date);
    } else if (date instanceof Date) {
      return date;
    } else {
      return undefined;
    }
  },
  formatPeriodDate: (date: Date, hideDays: boolean, showFiscalWeek: boolean, dateOffset: number = 0): string => {
    if (isNullOrUndefined(date)) {
      return '';
    }
    const yearData: CalYear = buildCalendarYear(date, dateOffset);
    let period: Period;
    let week: Week;
    yearData.periods.forEach((p: Period) => {
      if (p.startDate <= date && p.endDate >= date) {
        period = p;
      }
    });
    let fiscalWeekNumber: number = 0;
    period.weeks.forEach((w: Week, i: number) => {
      if (w.startDate <= date && w.endDate >= date) {
        week = w;
        fiscalWeekNumber = i + 1;
      }
    });

    const weekNumber: number = showFiscalWeek ? fiscalWeekNumber : week.week;

    let result: string = `${period.year}/P${period.period}/W${weekNumber}`;

    if (!hideDays) {
      result += `/${dateConst.daysOfWeekNames[date.getDay()]}`;
    }

    return result;
  },
  getFiscalYear: (date: Date): number => {
    return calculateFiscalStart(date).getFullYear();
  },
  getStartOfWeek: (date: Date): Date => {
    const dayOfWeek: number = date.getDay();
    if (dayOfWeek === 0) {
      return date;
    }

    return date.addDays(0 - dayOfWeek);
  },
  isSameWeek: (date1: Date, date2: Date): boolean => {
    if (date1 == null || date2 == null) {
      return false;
    }
    return dateConst.isSameDate(dateConst.getStartOfWeek(date1), dateConst.getStartOfWeek(date2));
  },
  validateMinMax: (date: Date, minDate: string, maxDate: string, warn: boolean = false): DateValidationResult => {
    const outOfRangeMessage: string = 'Date is outside of the min and max range';

    const dateToCheck: Date =
      new Date(date.getFullYear(), date.getMonth(), date.getDate(), 0, 0, 0, 0);

    const result: DateValidationResult = { valid: true, maxValid: true, minValid: true };

    if (minDate != null) {
      const minActiveDate: Date = new Date(minDate);
      if (dateConst.dateIsInvalid(minActiveDate)) {
        if (warn) {
          console.warn(`Error parsing minActiveDate '${minDate}'`);
        }
      } else {
        const minValid: boolean = minActiveDate == null || minActiveDate <= dateToCheck;
        if (!minValid) {
          result.valid = false;
          result.minValid = false;
          if (dateConst.isSameWeek(dateToCheck, minActiveDate)) {
            result.minAvailableDate = minActiveDate;
          }
          if (warn) {
            console.warn(`Date is before available period ${dateToCheck}`);
            result.message = outOfRangeMessage;
          }
          return result;
        }
      }
    }

    if (maxDate != null) {
      const maxActiveDate: Date = new Date(maxDate);
      if (dateConst.dateIsInvalid(maxActiveDate)) {
        if (warn) {
          console.warn(`Error parsing minActiveDate '${maxDate}'`);
        }
      } else {
        const maxValid: boolean = maxActiveDate == null || maxActiveDate >= dateToCheck;
        if (!maxValid) {
          result.valid = false;
          result.maxValid = false;
          if (warn) {
            console.warn(`Date is after available period ${dateToCheck}`);
            result.message = outOfRangeMessage;
          }
          return result;
        }
      }
    }

    if (dateToCheck < dateConst.startOfEpoch) {
      result.valid = false;
      if (warn) {
        console.warn(`Date is before start of unix epoch: ${dateToCheck}`);
        result.message = outOfRangeMessage;
      }
      return result;
    }

    if (dateToCheck > dateConst.endOfEpoch) {
      result.valid = false;
      if (warn) {
        console.warn(`Date is after end of unix epoch: ${date}`);
        result.message = outOfRangeMessage;
      }
      return result;
    }

    return result;
  },
  datePartsInvalid: (year: number, month: number, dayOfMonth: number): boolean => {
    const monthValid: boolean = isNaN(month) || month < 0 || month > dateConst.maxMonthIndex;
    const dayValid: boolean = isNaN(dayOfMonth) || dayOfMonth < 0 || dayOfMonth > 31;
    const yearValid: boolean = isNaN(year) || year <= 999 || year <= 0;
    return monthValid || dayValid || yearValid;
  },
  composeYearList: (minActiveDate: string, maxActiveDate: string, referenceYear: number): Array<Item> => {
    const minDate: Date = new Date(minActiveDate);
    const noMinDate: boolean = minActiveDate == null || dateConst.dateIsInvalid(minDate);
    const maxDate: Date = new Date(maxActiveDate);
    const noMaxDate: boolean = maxActiveDate == null || dateConst.dateIsInvalid(maxDate);

    const fiscalMinYear: number = dateConst.getFiscalYear(minDate);
    const minYear: number = noMinDate ? referenceYear - 2 : fiscalMinYear;

    const fiscalMaxYear: number = dateConst.getFiscalYear(maxDate);
    const maxYear: number = noMaxDate ? referenceYear + 3 : fiscalMaxYear;

    return dateConst.rangeIncluding(minYear, maxYear).map((r) => ({ label: r + '', value: r + '' }));
  }
};

// If the calculated year doesn't currently exist on years[], let's add it to the beginning.
export function updateYearsOnCalendarChange(years: Item[], year: number) {
  const index = years.findIndex((it) => Number(it.label) === year);
  if (index === -1) {
    const addYear: any = { label: String(year), value: String(year) };
    years.unshift(addYear);
  }
  years.sort((a, b) => Number(a.label) - Number(b.label));
}


// Let's remove years from the list if they are below the minimum active year.
// This can happen when switching from Ad/Fiscal calendars to Gregorian.
export function getYearsInRange(minActiveDate: Date | string, years: Item[]) {
  const minActiveYear = new Date(minActiveDate).getFullYear();
  return years.filter((year) => Number(year.label) >= minActiveYear);
}

export function yearAccepted(minActiveDate: Date | string, maxActiveDate: Date | string, newYear: number): boolean {
  const yearGreaterThanMinActive: boolean = minActiveDate == null || newYear >= (new Date(minActiveDate)).getFullYear();
  const yearLessThanMaxActive: boolean = maxActiveDate == null || newYear <= (new Date(maxActiveDate)).getFullYear();

  return yearGreaterThanMinActive && yearLessThanMaxActive;
}
